# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import asyncio
import microcoapy
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse

class SensorResource(CoapResource):
    def __init__(self):
        super().__init__("/sensors/temp")
        self.temperature = 25.0
        
    def get(self, request):
        response = CoapResponse()
        response.payload = str(self.temperature).encode()
        response.code = 2.05
        return response
        
    def put(self, request):
        if request.payload:
            try:
                self.temperature = float(request.payload.decode())
                response = CoapResponse()
                response.code = 2.04
                return response
            except:
                response = CoapResponse()
                response.code = 4.00
                return response
        response = CoapResponse()
        response.code = 4.00
        return response

class ActuatorResource(CoapResource):
    def __init__(self):
        super().__init__("/actuators/light")
        self.light_status = False
        
    def get(self, request):
        response = CoapResponse()
        response.payload = str(self.light_status).encode()
        response.code = 2.05
        return response
        
    def put(self, request):
        if request.payload:
            try:
                payload = request.payload.decode().lower()
                if payload in ['true', '1', 'on']:
                    self.light_status = True
                elif payload in ['false', '0', 'off']:
                    self.light_status = False
                response = CoapResponse()
                response.code = 2.04
                return response
            except:
                response = CoapResponse()
                response.code = 4.00
                return response
        response = CoapResponse()
        response.code = 4.00
        return response

async def main():
    server = CoapServer("0.0.0.0", 5683)
    server.add_resource(SensorResource())
    server.add_resource(ActuatorResource())
    
    try:
        await server.start()
        print("CoAP server started on port 5683")
        while True:
            await asyncio.sleep(1)
    except KeyboardInterrupt:
        print("Server stopped")
        await server.stop()

if __name__ == "__main__":
    asyncio.run(main())